import { useState, useEffect, useCallback, useMemo } from 'react';
import { InfiniteScrollState, PaginationRequest, PaginatedResult, ApiResponse } from '@/types/api.types';
import { getHttpErrorMessage } from '@/utils/httpStatus';

export interface UseInfiniteScrollOptions<T> {
    fetchFunction: (paginationRequest: PaginationRequest) => Promise<{ data: ApiResponse<PaginatedResult<T>> }>;
    initialPageSize?: number;
    dependencies?: any[];
    autoLoad?: boolean; // Auto-load on mount and dependency changes
}

export function useInfiniteScroll<T>({
    fetchFunction,
    initialPageSize = 10,
    dependencies = [],
    autoLoad = true
}: UseInfiniteScrollOptions<T>) {
    const [state, setState] = useState<InfiniteScrollState<T>>({
        items: [],
        loading: false,
        hasMore: true,
        continuationToken: undefined,
        error: undefined
    });

    const [initialLoad, setInitialLoad] = useState(true);

    const loadMore = useCallback(async (reset: boolean = false) => {
        if (state.loading || (!state.hasMore && !reset)) return;

        setState(prev => ({
            ...prev,
            loading: true,
            error: undefined,
            ...(reset ? { items: [], continuationToken: undefined, hasMore: true } : {})
        }));

        try {
            const paginationRequest: PaginationRequest = {
                pageSize: initialPageSize,
                continuationToken: reset ? undefined : state.continuationToken
            };

            const response = await fetchFunction(paginationRequest);

            if (response.data.status >= 200 && response.data.status < 300) {
                const paginatedResult = response.data.result;
                const items = paginatedResult?.items || [];
                
                setState(prev => ({
                    ...prev,
                    items: reset ? items : [...prev.items, ...items],
                    loading: false,
                    hasMore: !!paginatedResult?.continuationToken,
                    continuationToken: paginatedResult?.continuationToken,
                    error: undefined
                }));
            } else {
                const errorMessage = getHttpErrorMessage(response.data.status);
                    
                setState(prev => ({
                    ...prev,
                    loading: false,
                    error: errorMessage,
                    hasMore: false
                }));
            }
        } catch (error) {
            const status = (error && typeof error === 'object' && 'response' in error)
                ? ((error as { response?: { status?: number } }).response?.status ?? 0)
                : 0;
            const errorMessage = getHttpErrorMessage(status);

            setState(prev => ({
                ...prev,
                loading: false,
                error: errorMessage,
                hasMore: false
            }));
        }
    }, [fetchFunction, initialPageSize, state.loading, state.hasMore, state.continuationToken]);

    const refresh = useCallback(() => {
        loadMore(true);
    }, [loadMore]);

    // Memoize dependencies to prevent unnecessary re-renders
    const memoizedDependencies = useMemo(() => dependencies, dependencies);

    useEffect(() => {
        if (autoLoad && initialLoad) {
            setInitialLoad(false);
            loadMore(true);
        } else if (autoLoad && !initialLoad) {
            // Auto-refresh when dependencies change
            loadMore(true);
        }
    }, [...memoizedDependencies, initialLoad, autoLoad]);

    // Memoize return value to prevent unnecessary re-renders
    return useMemo(() => ({
        items: state.items,
        loading: state.loading,
        hasMore: state.hasMore,
        error: state.error,
        loadMore: () => loadMore(false),
        refresh,
        totalItems: state.items.length
    }), [state.items, state.loading, state.hasMore, state.error, loadMore, refresh]);
}
